public static long parseOctal(final byte[] buffer, final int offset, final int length) {
    long result = 0;
    int end = offset + length;
    int start = offset;

    if (length < 2){
        throw new IllegalArgumentException("Length " + length + " must be at least 2");
    }

    // Remove leading zeros
    while (start < end && buffer[start] == '0') {
        start++;
    }

    // Skip leading spaces
    while (start < end && buffer[start] == ' ') {
        start++;
    }

    // Trim all trailing spaces and NULs
    while (end > start && (buffer[end - 1] == ' ' || buffer[end - 1] == 0)) {
        end--;
    }

    // Parse the octal string
    for (int i = start; i < end; i++) {
        if (buffer[i] < '0' || buffer[i] > '7') {
            throw new IllegalArgumentException(exceptionMessage(buffer, offset, length, i, buffer[i]));
        }
        result = (result << 3) + (buffer[i] - '0'); // convert from ASCII
    }
    return result;
}
